def find_and_replace_pattern(words: list[str], pattern: str) -> list[str]:
    def _encode_pattern(s: str) -> list[int]:
        char_to_code = {}
        next_code = 0
        encoded_representation = []
        for char in s:
            if char not in char_to_code:
                char_to_code[char] = next_code
                next_code += 1
            encoded_representation.append(char_to_code[char])
        return encoded_representation

    encoded_target_pattern = _encode_pattern(pattern)

    matching_words = []
    for word in words:
        if _encode_pattern(word) == encoded_target_pattern:
            matching_words.append(word)

    return matching_words
